(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn35"],{bd64:function(n,t){n.exports="### 模板语法\n  \n* Mustache语法: {{msg}}\n* Html赋值: v-html=\"\"\n* 绑定属性:v-bind:id=\"\"\n* 使用表达式: {{ok? 'YES':'NO'}}\n* 文本赋值:v-text=\"\"\n* 指令:v-if=\"\"\n* 过滤器: {{message|capitalize}} & v-bind.id=\"rowId | formatId\"\n\n### Class和Style绑定\n* 对象语法: v-bind:class=\"{active:isActive,'text-danger':hasError}\"\n* 数组语法: \n```html\n<div v-bind:class=\"[a,b]\"></div>\ndata:{\n  a:'aClass',\n  b:'bClass'\n}\n```\n* style绑定－对象语法: v-bind:style=\"{color:activeColor,fontSize:fontSize+'px'}\"\n\n### 条件渲染\n* v-if\n* v-else\n* v-else-if\n* v-show\n* v-cloak\n\n### vue 事件处理事件\n![avatar](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/vue/event.png)\n\n### Vue组件\n* 全局组件和局部组件\n* 父子组件通讯－数据传递\n* Slot\n\n![avatar](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/vue/component.png)\n* 子组件操作父组件数据。通过给父组件绑定自定义事件，子组件方法中使用this.$emit('自定义事件名')（此方法相当于jquery里面的trigger）来执行父组件的函数，从而改变父组件数据。\n* 如果想要子组件传值给父组件，通过this.$emit('自定义事件名','想传的值'）传递给父组件，父组件的该自定义事件回调方法的入参，即为你想传递的值。\n\n### 路由基础介绍\n\n#### 什么是前端路由？\n    路由是根据不同的url地址展示不同的\b内容和页面\n\n    前端路由就是把不同路由对应不同的内容或页面的任务交给前端来做，之前是通过服务端根据url的不同返回不同的页面实现的\n#### 什么时候使用前端路由？\n    在单页面应用，大部分页面结构不变，只改变部分内容的时候使用\n#### 前端路由有什么优点和缺点？\n    优点：\n        用户体验好，不需要每次从服务器全部获取，快速展现给用户\n    缺点：\n        不利于SEO\n        使用浏览器的前进，后退的时候会重新发请求，没有合理地\b利用缓存\n        单页面无法记录之前滚动的位置，无法在前进，后退的时候纪录滚动条的位置\n\n ```html     \n<router-link> this.$router.push({path:\"\"}) 等于A标签做跳转\n\n<router-view> 跳转之后渲染的位置\n```\n\n![avatar](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/vue/dtly.png)\n\n\n\n\n\n"},eac1:function(n,t,e){"use strict";e.r(t);var s=function(){var n=this,t=n.$createElement,s=n._self._c||t;return s("markdown",{attrs:{source:e("bd64")}})},a=[],i=e("2877"),r={},u=Object(i["a"])(r,s,a,!1,null,null,null);u.options.__file="vue.vue";t["default"]=u.exports}}]);